firmware_template.source:
#include "dumbdisplay_dashboard.h"
#include <WiFi.h>
#include "dumbdisplay.h"
#include "wifidumbdisplay.h"

#define MAX_SLOTS 6

static DDWiFiServerIO* ddio = nullptr;
static DumbDisplay* dd = nullptr;
static LcdDDLayer* labels[MAX_SLOTS];
static LedGridDDLayer* bars[MAX_SLOTS];
static int slot_count = 0;

void dd_dashboard_setup(const char* ssid, const char* password) {
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) { delay(500); }
  Serial.printf("[dd_dash] IP: %s\n", WiFi.localIP().toString().c_str());
  ddio = new DDWiFiServerIO(nullptr, nullptr, 10201);
  dd = new DumbDisplay(ddio);
  for (int i = 0; i < MAX_SLOTS; i++) {
    labels[i] = dd->createLcdLayer(16, 2);
    labels[i]->backgroundColor("black");
    bars[i] = dd->createLedGridLayer(10, 1);
    bars[i]->onColor("green");
    bars[i]->offColor("darkgray");
  }
  dd->configAutoPin(DD_AP_VERT);
  slot_count = MAX_SLOTS;
}

void dd_dashboard_loop() { /* DumbDisplay handles loop */ }

void dd_dashboard_set_value(int slot, const char* label, float value, const char* unit) {
  if (slot < 0 || slot >= slot_count) return;
  labels[slot]->clear();
  labels[slot]->setCursor(0, 0);
  labels[slot]->print(label);
  labels[slot]->setCursor(0, 1);
  char buf[32];
  snprintf(buf, sizeof(buf), "%.1f %s", value, unit);
  labels[slot]->print(buf);
}

void dd_dashboard_set_bar(int slot, float value, float max_val, const char* color) {
  if (slot < 0 || slot >= slot_count) return;
  bars[slot]->onColor(color);
  int filled = (int)((value / max_val) * 10.0f);
  if (filled > 10) filled = 10;
  for (int i = 0; i < 10; i++) {
    if (i < filled) bars[slot]->turnOn(i, 0);
    else bars[slot]->turnOff(i, 0);
  }
}
